function token() public view virtual
    returns (uint256 chainId, address tokenContract, uint256 tokenId)
{
    assembly {
        let m := mload(0x40)
        extcodecopy(address(), 0x00, 0x4d, 0x60) // 96 bytes from clone tail
        chainId := mload(0x00)
        tokenContract := mload(0x20) // upper 96 bits already clean
        tokenId := mload(0x40)
        mstore(0x40, m)
    }
}

function owner() public view virtual returns (address result) {
    uint256 cachedChainId = _cachedChainId;
    assembly {
        let m := mload(0x40)
        extcodecopy(address(), 0x00, 0x4d, 0x60)
        if eq(mload(0x00), cachedChainId) {
            let tokenContract := mload(0x20)
            // tokenId already at 0x40
            mstore(0x20, 0x6352211e) // ownerOf(uint256)
            result := mul(
                mload(0x20),
                and(
                    gt(returndatasize(), 0x1f),
                    staticcall(gas(), tokenContract, 0x3c, 0x24, 0x20, 0x20)
                )
            )
        }
        mstore(0x40, m)
    }
}
